var e=[{id:`L3_1`,type:`dialog`,speaker:`CHINATSU_NANA_NULL_NULL`,text:{KOREA:`<color=#ffd34c>나오님? 사나에!</color>`,JPN:`<color=#ffd34c>ナオ様？　早苗！</color>`,ENG:`<color=#ffd34c>Miss Nao? Sanae!</color>`,TWN:`<color=#ffd34c>奈緒大人？早苗！</color>`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:`CHINATSU_NANA_NULL_NULL`,text:{KOREA:`<color=#ffd34c>들리면 대답해주세요!</color>`,JPN:`<color=#ffd34c>聞こえたら返事してください！</color>`,ENG:`<color=#ffd34c>Answer if you can hear me!</color>`,TWN:`<color=#ffd34c>有聽到我的聲音嗎？回答我！</color>`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:`CHINATSU_NANA_NULL_NULL`,text:{KOREA:`침식파가 강해서 연락이 닿지 않아요.`,JPN:`侵食波が強くて連絡が取れません。`,ENG:`I cannot reach them. The Corruption ray is too strong.`,TWN:`侵蝕波太強聯絡不上。`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:{char_id:`CHINATSU_NANA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`CHIFUYU_NANA_NULL_NULL`,text:{KOREA:`괜찮으실 겁니다. 나오님도 함께 계시니까요.`,JPN:`大丈夫でしょう。ナオ様もご一緒ですから。`,ENG:`I am sure they are all right. Miss Nao is with her.`,TWN:`奈緒大人也在，不會有事的。`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:{char_id:`CHIFUYU_NANA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`CHINATSU_NANA_NULL_NULL`,text:{KOREA:`저도 그럴 거라고 생각은 하지만……`,JPN:`私もそうだとは思いますが……`,ENG:`I hope so too, but...`,TWN:`我也是這麼想的，可是……`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:{char_id:`CHINATSU_NANA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`OPR_NPC_NULL_NULL`,text:{KOREA:`뭐지? 갑자기 곳곳에서 침식반응이……?`,JPN:`何だ？　いきなりあちこちで侵食反応が……？`,ENG:`Huh? Corruption responses are emerging all over the place...?`,TWN:`怎麼這樣？突然到處都有侵蝕反應……？`},stage:{bg:`SKY_NIGHT`,slots:{L:null,C:null,R:null}}},{id:`L11_1`,type:`dialog`,speaker:`OPR_NPC_NULL_NULL`,text:{KOREA:`침식체 활동신호가 포착됐습니다! 분류되지 않은 타입!`,JPN:`侵食体の活動信号を確認しました！　未分類タイプ！`,ENG:`C.O. activity detected! Type unidentified!`,TWN:`發現侵蝕體蹤跡！是沒分類的類型！`},stage:{bg:`SKY_NIGHT`,slots:{L:null,C:null,R:null}}},{id:`L13_1`,type:`dialog`,speaker:`COMMANDER_NPC_NULL_NULL`,text:{KOREA:`미확인이라고? 대체 어디서 문제가 발생한 건가.`,JPN:`未確認だと？　いったいどこで問題が発生したんだ。`,ENG:`Unidentified? What's going on?!`,TWN:`沒分類？到底是從哪裡發生的？`},stage:{bg:`SKY_NIGHT`,slots:{L:null,C:{char_id:`COMMANDER_NPC_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`OPR_NPC_NULL_NULL`,text:{KOREA:`발생 위치는……!`,JPN:`発生位置は……！`,ENG:`Pinpointing location...!`,TWN:`發生位置……！`},stage:{bg:`SKY_NIGHT`,slots:{L:null,C:{char_id:`COMMANDER_NPC_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`OPR_NPC_NULL_NULL`,text:{KOREA:`특정이 안 됩니다! 도시 전역에서 침식파가 쏟아지고 있어요!`,JPN:`特定できません！　都市の全域から侵食波が溢れています！`,ENG:`Unable to pinpoint location! Corruption rays are all throughout the city!`,TWN:`不是特定地區！全城都受到侵蝕波影響！`},stage:{bg:`SKY_NIGHT`,slots:{L:null,C:{char_id:`COMMANDER_NPC_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`COMMANDER_NPC_NULL_NULL`,text:{KOREA:`뭐? 하지만 아직 육안으로는 아무것도……`,JPN:`何？　だが肉眼ではまだ何も……`,ENG:`What?! But we don't see anything–`,TWN:`什麼？但我現在什麼都沒看……`},stage:{bg:`SKY_NIGHT`,slots:{L:null,C:{char_id:`COMMANDER_NPC_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:null,text:{KOREA:`침식체다! 잡아!`,JPN:`侵食体だ！　捕まえろ！`,ENG:`It's a C.O.! Kill it!`,TWN:`是侵蝕體！攻擊！`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:null,R:null}}},{id:`L22_1`,type:`dialog`,speaker:null,text:{KOREA:`뭐, 뭐였지? 어디에 있는지 안 보여……!`,JPN:`な、なんだったんだ？　どこにいるのか見えない……！`,ENG:`W-what? I can't see where it is...!`,TWN:`什…什麼？我什麼都沒看到……！`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:null,R:null}}},{id:`L23_1`,type:`dialog`,speaker:`CHINATSU_NANA_NULL_NULL`,text:{KOREA:`저건……?`,JPN:`あれは……？`,ENG:`Is that...?`,TWN:`那是……？`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:{char_id:`CHINATSU_NANA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`CHIFUYU_NANA_NULL_NULL`,text:{KOREA:`기척은 뚜렷하지만 눈에는 보이지 않는군요.`,JPN:`気配ははっきりしていますが、目には見えませんね。`,ENG:`I can feel it, but cannot see it.`,TWN:`雖然可以明顯感受到動靜，肉眼卻看不到。`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:{char_id:`CHIFUYU_NANA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`CHINATSU_NANA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L28_1`,type:`dialog`,speaker:`CHIFUYU_NANA_NULL_NULL`,text:{KOREA:`제 곁에서 멀어지지 마십시오, 당주님.`,JPN:`私のそばを離れないでください、当主。`,ENG:`Lady Nanahara, please stay behind me.`,TWN:`堂主，請不要在離我太遠的地方。`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:{char_id:`CHIFUYU_NANA_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`CHINATSU_NANA_NULL_NULL`,face:`UNIT_IDLE`}}}}];export{e as default};